import{_ as t,o as e,c as l,ai as r}from"./chunks/framework.DjxHwWNk.js";const b=JSON.parse('{"title":"Свято-Троицкий кафедральный собор / бывший ДК Автомобилистов","description":"Место первого рок-фестиваля в Свердловске и одна из отправных точек истории уральского рока.","frontmatter":{"title":"Свято-Троицкий кафедральный собор / бывший ДК Автомобилистов","description":"Место первого рок-фестиваля в Свердловске и одна из отправных точек истории уральского рока.","outline":"deep"},"headers":[],"relativePath":"places/dk-avtomobilistov.md","filePath":"places/dk-avtomobilistov.md"}'),o={name:"places/dk-avtomobilistov.md"};function s(d,a,i,n,h,p){return e(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="свято-троицкии-кафедральныи-собор-бывшии-дк-автомобилистов" tabindex="-1">Свято-Троицкий кафедральный собор / бывший ДК Автомобилистов <a class="header-anchor" href="#свято-троицкии-кафедральныи-собор-бывшии-дк-автомобилистов" aria-label="Permalink to “Свято-Троицкий кафедральный собор / бывший ДК Автомобилистов”">​</a></h1><p><strong>Свято-Троицкий кафедральный собор</strong>, ранее известный как <strong>ДК Автомобилистов</strong>, — одно из самых важных мест в истории уральского рока. Именно здесь 6 июня 1981 года состоялся первый в истории Свердловска рок-фестиваль, который принято считать одной из отправных точек всего движения.</p><div class="tip custom-block"><p class="custom-block-title">Кратко</p><ul><li><strong>Адрес:</strong> Екатеринбург, ул. Розы Люксембург, 57</li><li><strong>Период ключевого значения:</strong> 1981 год, конец 1980-х годов</li><li><strong>Главная роль:</strong> место первого свердловского рок-фестиваля</li><li><strong>Связанные группы:</strong> «Урфин Джюс», «Трек», «Р-Клуб», «Настя»</li><li><strong>Статус сегодня:</strong> действующий православный храм — Свято-Троицкий кафедральный собор</li></ul></div><h2 id="почему-это-место-важно" tabindex="-1">Почему это место важно <a class="header-anchor" href="#почему-это-место-важно" aria-label="Permalink to “Почему это место важно”">​</a></h2><p>Бывший ДК «Автомобилистов» важен как точка, с которой начинается публичная история свердловской рок-сцены. До открытия Свердловского рок-клуба оставалось ещё пять лет, но именно здесь в 1981 году рок-музыка впервые громко заявила о себе как о городском культурном явлении.</p><p>Фестиваль проходил полулегально, в условиях, когда рок ещё не имел официального признания. Несмотря на это, событие собрало полный зал и стало первым большим сценическим опытом для многих свердловских музыкантов. Позже именно такие события подготовили почву для появления Свердловского рок-клуба.</p><h2 id="историческая-справка" tabindex="-1">Историческая справка <a class="header-anchor" href="#историческая-справка" aria-label="Permalink to “Историческая справка”">​</a></h2><p>Здание было построено в конце 1970-х годов как Дом культуры «Автомобилистов» — типичный советский дворец культуры для рабочих Уральского автомобильного завода. Такие площадки создавались для концертов, кружков, собраний и культурной жизни заводских коллективов.</p><p>Однако в историю уральского рока здание вошло благодаря событию, которое сегодня воспринимается как начало большого музыкального движения. <strong>6 июня 1981 года</strong> в ДК «Автомобилистов» состоялся первый в истории Свердловска рок-фестиваль.</p><p>Фестиваль был организован энтузиастами и проходил в полулегальном формате. В то время рок-музыка ещё не была частью официальной культурной политики, поэтому само проведение такого события выглядело смелым шагом. По воспоминаниям очевидцев, зал был переполнен, а интерес публики оказался настолько большим, что часть зрителей, оставшихся без билетов, всё равно пустили внутрь.</p><p>На сцене выступили первые свердловские рок-группы, многие из которых позднее вошли в историю уральского рока: <strong>«Урфин Джюс»</strong>, <strong>«Трек»</strong>, <strong>«Р-Клуб»</strong> и другие коллективы. Для многих участников это был первый опыт выхода на большую сцену и важный шаг к формированию будущей рок-сцены города.</p><p>В конце 1980-х годов, уже после официального открытия Свердловского рок-клуба, в ДК «Автомобилистов» также проходили отдельные концерты и фестивали, связанные с рок-клубной средой.</p><p>В 1990-е годы здание было передано Русской православной церкви и освящено как Свято-Троицкий кафедральный собор. Несмотря на смену статуса, память о первом рок-фестивале сохранилась в городской культурной истории.</p><h2 id="геолокация" tabindex="-1">Геолокация <a class="header-anchor" href="#геолокация" aria-label="Permalink to “Геолокация”">​</a></h2><p><strong>Адрес:</strong> Екатеринбург, ул. Розы Люксембург, 57.</p><p>Здание находится в центральной части Екатеринбурга и может быть включено в пешие маршруты по ранней истории уральского рока.</p><h2 id="связанные-лица" tabindex="-1">Связанные лица <a class="header-anchor" href="#связанные-лица" aria-label="Permalink to “Связанные лица”">​</a></h2><table tabindex="0"><thead><tr><th>Имя</th><th>Роль / связь с объектом</th></tr></thead><tbody><tr><td><a href="/Knowledge-Base/people/nastya-poleva.html">Настя Полева</a></td><td>Одна из участниц первых фестивалей, связана с группой «Настя»</td></tr><tr><td><a href="/Knowledge-Base/people/evgeny-gorenburg.html">Евгений Горенбург</a></td><td>Организатор многих ранних концертов, позднее первый директор Свердловского рок-клуба</td></tr><tr><td><a href="/Knowledge-Base/people/alexey-karasyuk.html">Алексей Карасюк</a></td><td>Историк уральского рока, задокументировавший событие в книге «Свердловский рок»</td></tr><tr><td>Музыканты групп «Урфин Джюс», «Трек», «Р-Клуб»</td><td>Участники первого рок-фестиваля 1981 года</td></tr></tbody></table><h2 id="связанные-группы" tabindex="-1">Связанные группы <a class="header-anchor" href="#связанные-группы" aria-label="Permalink to “Связанные группы”">​</a></h2><ul><li><a href="/Knowledge-Base/bands/urfin-dzhus.html">Урфин Джюс</a></li><li><a href="/Knowledge-Base/bands/trek.html">Трек</a></li><li><a href="/Knowledge-Base/bands/r-club.html">Р-Клуб</a></li><li><a href="/Knowledge-Base/bands/nastya.html">Настя</a></li></ul><h2 id="современныи-статус" tabindex="-1">Современный статус <a class="header-anchor" href="#современныи-статус" aria-label="Permalink to “Современный статус”">​</a></h2><p>Сегодня здание является действующим православным храмом — <strong>Свято-Троицким кафедральным собором</strong>. Его основная функция изменилась, но историческая связь с уральским роком остаётся важной частью культурной памяти города.</p><p>Для базы знаний это место особенно важно как пример того, как городская локация может иметь несколько исторических слоёв: советский дворец культуры, площадка первого рок-фестиваля и современный религиозный объект.</p><div class="warning custom-block"><p class="custom-block-title">Важно для туристов</p><p>Сейчас это действующий храм, поэтому при посещении важно соблюдать правила поведения, учитывать расписание богослужений и относиться к месту с уважением. Экскурсионный формат лучше уточнять заранее.</p></div><h2 id="роль-в-2026-году" tabindex="-1">Роль в 2026 году <a class="header-anchor" href="#роль-в-2026-году" aria-label="Permalink to “Роль в 2026 году”">​</a></h2><p>В рамках Года уральского рока это место планируется включить в экскурсионные маршруты как точку зарождения свердловского рок-движения.</p><p>Также в материалах проекта указана возможная установка памятной таблички, которая зафиксирует историческое значение бывшего ДК «Автомобилистов» для уральской рок-культуры.</p><h2 id="планируемые-события" tabindex="-1">Планируемые события <a class="header-anchor" href="#планируемые-события" aria-label="Permalink to “Планируемые события”">​</a></h2><table tabindex="0"><thead><tr><th>Период</th><th>Событие</th></tr></thead><tbody><tr><td>2026 год</td><td>Возможная установка памятной таблички о первом рок-фестивале</td></tr><tr><td>2026 год</td><td>Включение здания в экскурсии по ранним рок-местам Екатеринбурга</td></tr><tr><td>2026 год</td><td>Посещение собора как точки зарождения уральского рок-движения в рамках городских маршрутов</td></tr></tbody></table><h2 id="что-посмотреть-рядом" tabindex="-1">Что посмотреть рядом <a class="header-anchor" href="#что-посмотреть-рядом" aria-label="Permalink to “Что посмотреть рядом”">​</a></h2><p>Свято-Троицкий кафедральный собор можно включать в маршрут по центральным и ранним рок-местам Екатеринбурга. Его удобно связать с другими точками базы знаний:</p><ul><li><a href="/Knowledge-Base/places/dk-sverdlova.html">ДК имени Свердлова</a></li><li><a href="/Knowledge-Base/places/dvorets-molodezhi.html">Дворец молодёжи</a></li><li><a href="/Knowledge-Base/places/pryanik-urgahu.html">УрГАХУ, корпус «Пряник»</a></li><li><a href="/Knowledge-Base/places/bashlachev-house.html">Дом Александра Башлачёва</a></li></ul>',32)])])}const g=t(o,[["render",s]]);export{b as __pageData,g as default};
